mapper.select:
SELECT create_time, accessType AS action
FROM aro_access_log
WHERE user_id = #{userId}
  AND create_time >= #{todayStart}
ORDER BY create_time ASC

SELECT total_exp
FROM aro_personnel
WHERE user_id = #{userId}

SELECT r.room_id AS roomId, (SELECT al.room_name FROM aro_access_log al WHERE al.room_id = r.room_id AND al.room_name IS NOT NULL AND TRIM(al.room_name) != '' ORDER BY al.create_time DESC LIMIT 1) AS roomName FROM (SELECT DISTINCT room_id AS room_id FROM aro_access_log WHERE room_id IN
#{rid}
) r
